import{_ as t,o as a,c as e,a2 as r}from"./chunks/framework.Pywvta2k.js";const p=JSON.parse('{"title":"刘力红","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/05-近现代/06-刘力红.md","filePath":"tcm-data/05-近现代/06-刘力红.md","lastUpdated":1781084559000}'),l={name:"tcm-data/05-近现代/06-刘力红.md"};function n(s,o,i,c,h,u){return a(),e("div",null,[...o[0]||(o[0]=[r('<h1 id="刘力红" tabindex="-1">刘力红 <a class="header-anchor" href="#刘力红" aria-label="Permalink to &quot;刘力红&quot;">​</a></h1><blockquote><p>刘力红（1958年生），湖南湘西人 代表作：《思考中医》（又名《伤寒论导论》） 当代中医文化复兴的推动者</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>经历</strong>：甘肃中医学院毕业，南京中医药大学博士</li><li><strong>师承</strong>：李阳波（民间医家）、邓铁涛（国医大师）、卢崇汉（火神派）</li><li><strong>现任</strong>：广西中医药大学教授</li><li><strong>代表作</strong>：《思考中医》——<strong>近20年销量最大的中医著作之一</strong></li></ul><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-回归经典" tabindex="-1">1. 回归经典 <a class="header-anchor" href="#_1-回归经典" aria-label="Permalink to &quot;1. 回归经典&quot;">​</a></h3><blockquote><p><strong>「中医的核心在经典，经典的突破口在《伤寒论》。」</strong></p></blockquote><p>刘力红认为，当代中医的困境在于脱离经典，必须以《内经》和《伤寒论》为根本。</p><h3 id="_2-医易同源" tabindex="-1">2. 医易同源 <a class="header-anchor" href="#_2-医易同源" aria-label="Permalink to &quot;2. 医易同源&quot;">​</a></h3><p>刘力红特别强调<strong>易经对中医的影响</strong>，认为不懂《周易》就难以深入理解中医的阴阳理论。</p><h3 id="_3-火神派传承" tabindex="-1">3. 火神派传承 <a class="header-anchor" href="#_3-火神派传承" aria-label="Permalink to &quot;3. 火神派传承&quot;">​</a></h3><p>刘力红师从卢崇汉（火神派传人），重视扶阳，但强调**&quot;扶阳不是滥用附子&quot;**：</p><blockquote><p><strong>「扶阳者，扶生命之阳也，非扶附子之阳。」</strong></p></blockquote><hr><h2 id="三、经典名言" tabindex="-1">三、经典名言 <a class="header-anchor" href="#三、经典名言" aria-label="Permalink to &quot;三、经典名言&quot;">​</a></h2><blockquote><p><strong>「思考中医，就是思考生命。」</strong></p></blockquote><blockquote><p><strong>「中医的核心在经典，经典的突破口在《伤寒论》。」</strong></p></blockquote><blockquote><p><strong>「经方不是万能的，但没有经方是万万不能的。」</strong></p></blockquote><blockquote><p><strong>「中医的复兴，不是靠几个名医，而是要靠成千上万的基层中医。」</strong></p></blockquote><blockquote><p><strong>「养生不是吃补药，而是顺应自然。」</strong></p></blockquote><blockquote><p><strong>「治病的最高境界，是恢复人体的自愈能力。」</strong></p></blockquote><hr><h2 id="四、对后世的影响" tabindex="-1">四、对后世的影响 <a class="header-anchor" href="#四、对后世的影响" aria-label="Permalink to &quot;四、对后世的影响&quot;">​</a></h2><ul><li>《思考中医》带动了<strong>全民读伤寒</strong>的热潮</li><li>推动了经方在现代的复兴</li><li>促进了中医文化在大众中的普及</li></ul><hr><p><em>本条目为精简框架版。可扩展至《思考中医》要点精读、伤寒论导论、火神派传承等专题。</em></p>',28)])])}const q=t(l,[["render",n]]);export{p as __pageData,q as default};
